import numpy as np
im=Image.open('chess_board.png').convert('RGB')
arr=np.asarray(im).astype(int)
W=arr.shape[0]; sq=W//8
light=np.array([240,217,181]); dark=np.array([181,136,99])
files='abcdefgh'
def mask(r,c):
    block=arr[r*sq:(r+1)*sq, c*sq:(c+1)*sq]
    dl=np.abs(block-light).sum(2); dd=np.abs(block-dark).sum(2)
    fg=(dl>60)&(dd>60)
    return fg, block
occ=[]
masks={}
colors={}
for r in range(8):
    for c in range(8):
        fg,block=mask(r,c)
        if fg.sum()>200:
            occ.append((r,c))
            masks[(r,c)]=fg.astype(float)
            br=block[fg].mean()
            colors[(r,c)]='W' if br>150 else 'B'
# cluster by IoU on fg masks
keys=occ
def iou(a,b):
    A=masks[a]>0; B=masks[b]>0
    return (A&B).sum()/((A|B).sum()+1e-9)
clusters=[]
