for k in keys:
    placed=False
    for ci,rep in enumerate(clusters):
        if colors[k]==colors[rep] and iou(k,rep)>0.75:
            assigned[k]=ci; placed=True; break
    if not placed:
        assigned[k]=len(clusters); clusters.append(k)
